import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.DACwFHq9.js";const m=JSON.parse('{"title":"Export & Import Reference","description":"Complete reference for all Notely export and import features — workspace exports, PDF/HTML rendering, note packages, and workspace bundles.","frontmatter":{"title":"Export & Import Reference","description":"Complete reference for all Notely export and import features — workspace exports, PDF/HTML rendering, note packages, and workspace bundles.","keywords":"export, import, PDF, HTML, workspace, note package, zip, AES-256","category":"User Guide"},"headers":[],"relativePath":"export-reference.md","filePath":"export-reference.md","lastUpdated":1784869909000}'),d={name:"export-reference.md"};function n(s,e,i,l,c,p){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="export-import-reference" tabindex="-1">Export &amp; Import Reference <a class="header-anchor" href="#export-import-reference" aria-label="Permalink to &quot;Export &amp; Import Reference&quot;">​</a></h1><p>Notely provides three distinct export systems depending on the scope and format needed:</p><table tabindex="0"><thead><tr><th>System</th><th>Scope</th><th>Format</th><th>Where to find</th></tr></thead><tbody><tr><td><strong>Single Note Export</strong></td><td>One note</td><td>PDF, HTML</td><td>File menu or Toolbar button</td></tr><tr><td><strong>Workspace Export</strong></td><td>Entire workspace</td><td><code>.zip</code> (Raw, PDF, or Web)</td><td>File → Export Workspace</td></tr><tr><td><strong>Note Package</strong></td><td>Selected notes + assets</td><td><code>.note</code> (encrypted bundle)</td><td>File → Export / Import Note Package</td></tr></tbody></table><hr><h2 id="_1-single-note-export-pdf-html" tabindex="-1">1. Single Note Export (PDF &amp; HTML) <a class="header-anchor" href="#_1-single-note-export-pdf-html" aria-label="Permalink to &quot;1. Single Note Export (PDF &amp; HTML)&quot;">​</a></h2><p>Exports the currently active markdown note as a standalone rendered document.</p><h3 id="pdf-export" tabindex="-1">PDF Export <a class="header-anchor" href="#pdf-export" aria-label="Permalink to &quot;PDF Export&quot;">​</a></h3><ul><li>Renders the note through a <strong>Headless Chromium</strong> window with the active Notely theme CSS applied.</li><li><strong>Local media resolved</strong>: Embedded images and diagrams are referenced via their absolute file:// paths before rendering.</li><li><strong>Mermaid diagrams</strong> and <strong>LaTeX equations</strong> are rendered as vector SVG and KaTeX HTML inside the PDF.</li><li>Output path defaults to the last-used export directory. The app remembers the path (<code>getLastPdfExportPath</code>).</li><li>PDF write failures (EPERM, EBUSY on OneDrive paths) are automatically retried up to 3 times with increasing delays (120ms → 320ms → 700ms).</li></ul><h3 id="html-export" tabindex="-1">HTML Export <a class="header-anchor" href="#html-export" aria-label="Permalink to &quot;HTML Export&quot;">​</a></h3><ul><li>Produces a self-contained HTML file with inline CSS and resolved media references.</li><li>Suitable for publishing notes to static web servers or opening in any browser without Notely.</li></ul><hr><h2 id="_2-workspace-export-full-zip-bundle" tabindex="-1">2. Workspace Export (Full ZIP Bundle) <a class="header-anchor" href="#_2-workspace-export-full-zip-bundle" aria-label="Permalink to &quot;2. Workspace Export (Full ZIP Bundle)&quot;">​</a></h2><p>Exports the entire active workspace as a <code>.zip</code> archive. Accessed via <strong>File → Export Workspace</strong>.</p><h3 id="export-modes" tabindex="-1">Export Modes <a class="header-anchor" href="#export-modes" aria-label="Permalink to &quot;Export Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>What is exported</th></tr></thead><tbody><tr><td><strong>Raw Docs</strong> (<code>raw</code>)</td><td>Plain <code>.md</code> files as-is, preserving original workspace folder structure</td></tr><tr><td><strong>PDF</strong> (<code>pdf</code>)</td><td>Each note rendered to a themed PDF file inside the archive</td></tr><tr><td><strong>Web / HTML</strong> (<code>web</code>)</td><td>Each note rendered to a standalone HTML page</td></tr></tbody></table><h3 id="content-modes-for-pdf-web" tabindex="-1">Content Modes (for PDF &amp; Web) <a class="header-anchor" href="#content-modes-for-pdf-web" aria-label="Permalink to &quot;Content Modes (for PDF &amp; Web)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Content Mode</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Combined</strong></td><td>Raw notes and cleansed/structured content merged into one file per note</td></tr><tr><td><strong>Separate</strong></td><td>Raw and Cleansed versions saved as separate files per note</td></tr><tr><td><strong>Raw Only</strong></td><td>Only raw markdown source content</td></tr><tr><td><strong>Cleansed Only</strong></td><td>Only the structured/processed note content</td></tr></tbody></table><h3 id="archive-structure" tabindex="-1">Archive Structure <a class="header-anchor" href="#archive-structure" aria-label="Permalink to &quot;Archive Structure&quot;">​</a></h3><ul><li>The ZIP root folder is named after the workspace (sanitized): <code>{workspaceName}_docs_DD_MM_YYYY.zip</code>.</li><li>Hidden subsystem directories (<code>.notes-app/</code>, <code>.git/</code>) are excluded from all workspace exports.</li><li>A progress event stream (<code>workspace-export:progress</code>) reports real-time file count progress to the UI.</li></ul><hr><h2 id="_3-note-package-export-import-note-bundle" tabindex="-1">3. Note Package Export &amp; Import (<code>.note</code> Bundle) <a class="header-anchor" href="#_3-note-package-export-import-note-bundle" aria-label="Permalink to &quot;3. Note Package Export &amp; Import (`.note` Bundle)&quot;">​</a></h2><p>For sharing specific notes between Notely users. Accessed via <strong>File → Export / Import Note Package</strong>.</p><h3 id="exporting-a-package" tabindex="-1">Exporting a Package <a class="header-anchor" href="#exporting-a-package" aria-label="Permalink to &quot;Exporting a Package&quot;">​</a></h3><ol><li><strong>Select notes</strong> — choose any <code>.md</code> files from the current workspace.</li><li><strong>Save location</strong> — defaults to <code>{workspaceName}.note</code>. Click <strong>Browse</strong> to choose a different path.</li><li><strong>Password (Optional)</strong> — restricts import. Stores a salted SHA-256 password hash in the bundle manifest.</li><li>Click <strong>Export Package</strong>.</li></ol><p><strong>What gets bundled:</strong></p><table tabindex="0"><thead><tr><th>Asset</th><th>Source Path</th><th>Included</th></tr></thead><tbody><tr><td>Markdown notes</td><td><code>{workspace}/**/*.md</code></td><td>✅</td></tr><tr><td>Images / screenshots</td><td><code>media/images/</code></td><td>✅</td></tr><tr><td>Excalidraw diagrams</td><td><code>.notes-app/excali-diagrams/</code></td><td>✅</td></tr><tr><td>Draw.io diagrams + thumbnails</td><td><code>media/draw.io/</code></td><td>✅</td></tr><tr><td>Package metadata manifest</td><td><code>metadata.json</code> inside bundle</td><td>✅ auto-generated</td></tr></tbody></table><p>Assets that are locked, missing, or inaccessible at export time are silently skipped — the note is still exported.</p><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><strong>AES-256 encrypted</strong> bundle — not readable by generic ZIP tools.</li><li>Every file in the bundle is <strong>SHA-256 hashed</strong> and the hashes are verified on import. Tampered packages are rejected.</li><li>Password protection stores a salted SHA-256 signature in the manifest. The password is verified in memory before any files are written.</li></ul><h3 id="importing-a-package" tabindex="-1">Importing a Package <a class="header-anchor" href="#importing-a-package" aria-label="Permalink to &quot;Importing a Package&quot;">​</a></h3><ol><li>Switch to the <strong>Import Package</strong> tab.</li><li>Click <strong>Browse</strong> and select a <code>.note</code> file.</li><li>Click <strong>Import Package</strong>.</li><li>Enter the password if prompted.</li></ol><p>Notely will:</p><ul><li>Decrypt and verify bundle integrity.</li><li>Authenticate the password against the manifest signature.</li><li>Copy notes into the workspace root (or appropriate subfolder).</li><li>Restore all media assets to their original relative paths.</li><li><strong>Resolve filename collisions</strong> automatically — existing files are never overwritten.</li><li>Reload the workspace document list so imported notes appear immediately.</li></ul><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely Cause</th><th>Fix</th></tr></thead><tbody><tr><td>&quot;Export failed: EPERM&quot;</td><td>Destination inside an actively syncing OneDrive path</td><td>Wait a moment and retry, or choose a local (non-OneDrive) folder</td></tr><tr><td>&quot;Import failed: integrity check&quot;</td><td><code>.note</code> file was modified or corrupted in transit</td><td>Request a fresh export from the sender</td></tr><tr><td>&quot;Incorrect password&quot;</td><td>Password doesn&#39;t match package hash</td><td>Confirm password with the package creator</td></tr><tr><td>Notes appear in workspace root</td><td>Package was exported from a flat workspace</td><td>Expected — import mirrors the original layout</td></tr><tr><td>PDF looks wrong on export</td><td>Note uses unsupported CSS or external fonts</td><td>Use built-in Notely themes; avoid <code>@import</code> of remote fonts</td></tr></tbody></table>',36)])])}const g=t(d,[["render",n]]);export{m as __pageData,g as default};
